# Prompt: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

from flask import redirect, url_for, session

def login_redirect(user, intended_destination='/'):
    try:
        session.permanent = True
        if intended_destination == '/':
            return redirect(url_for('user dashboard'))
        else:
            return redirect(intended_destination)
    except Exception as e:
        print(f"Error occurred: {e}")